3_real_world_example.code:
// Custom async function using the Error-First pattern
function fetchUserData(userId, callback) {
  setTimeout(() => {
    if (userId < 0) {
      // Failure: Pass error as the first argument
      callback(new Error('Invalid user ID'), null);
    } else {
      // Success: Pass null for the error, and data for the second
      callback(null, { id: userId, name: 'Alice' });
    }
  }, 500);
}

// Consuming the function
fetchUserData(-1, (err, user) => {
  if (err) {
    console.error('Error occurred:', err.message); // Output: Error occurred: Invalid user ID
    return; // Stop execution
  }

  console.log('User found:', user);
});

