function buggyAsync(callback) {
  setTimeout(() => {
    callback(null, 'Result A');
    // Bug: calls the callback again!
    callback(null, 'Result B'); 
  }, 100);
}

buggyAsync((err, data) => {
  console.log('Received:', data); 
  // Runs twice, potentially breaking application state
});
